use regex::Regex;
use std::collections::HashMap;
use std::error::Error;
use std::fmt;

#[derive(Debug)]
struct LineParseError {
    line: String,
    message: String,
}

impl fmt::Display for LineParseError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "Error parsing line '{}': {}", self.line, self.message)
    }
}

impl Error for LineParseError {}

fn parse_line(line: &str) -> Result<Vec<String>, LineParseError> {
    let re_general_ln = Regex::new(r"(java:\d+])").unwrap();
    let re_general = Regex::new(r"(.*?)(java:\d+])").unwrap();
    let re_split = Regex::new(r"(.*?)(java:\d+]) (.*)").unwrap();
    let re_thread = Regex::new(r"\[.*?-\d+-").unwrap();
    let re_thread_clean = Regex::new(r"^.*?#|]").unwrap();
    let re_solicitudes = Regex::new(r"solicitudes-").unwrap();
    let re_insertado = Regex::new(r"-Insertado").unwrap();
    let re_tag_split = Regex::new(r" - ").unwrap();
    let re_special_cases = Regex::new(r"Insertado el mensaje de (externa|intermediacion)").unwrap();

    let mut parts = line.splitn(4, "java:");
    let general = parts.next().unwrap_or("");
    let general_ln = parts.next().unwrap_or("");
    let (mut general_clean, log) = re_split.split(line).next().unwrap().split_at(general.len() + general_ln.len() + 6);

    let date = general_clean[..8].trim().to_string();
    let time = general_clean[8..16].trim().to_string();
    let level = general_clean[16..].trim().to_string();
    let thread = re_thread.replace_all(&log, "").to_string();
    thread = re_thread_clean.replace_all(&thread, "").to_string();
    if !thread.is_empty() {
        thread = format!("#{}", thread);
    }
    log = log.trim_end_matches(' ').to_string();

    let mut parts = re_tag_split.split(log).collect::<Vec<_>>();
    let pet_type = parts.remove(0).replace("- ", "").to_string();
    let tag = parts.remove(0).trim().to_string();
    tag = tag.replace("[", "").replace("]", "");

    if tag == "DBIMSG" {
        if parts[0] == "Insertado el mensaje de peticion externa" {
            tag = "DBIMSG_PE";
        } else if parts[] == "Insertado el mensaje de respuesta externa" {
            tag = "DBIMSG_RE";
        } else if parts[0] == "Insertado el mensaje de peticion intermediacion" {
            tag = "DBIMSG_PI";
        } else if parts[0] == "Insertado el mensaje de respuesta intermediacion" {
            tag = "DBIMSG_RI";
        } else {
            return Err(LineParseError {
                line: line.to_string(),
                message: format!("No se esperaba mensaje: {} en línea", parts[0]),
            });
        }
    }

    if tag.contains("-") {
        if tag.starts_with("DBIEXT") || tag.starts_with("DBIINT") || tag.starts_with("DBUEXT") || tag.starts_with("DBUINT") {
            let (cod_estado, cod_error) = parts[0].split_at(parts[0].len() - 1);
            parts.remove(0);
            parts.insert(0, cod_estado.trim().to_string());
            parts.insert(1, cod_error.trim().to_string());
        } else if tag.starts_with("SCHSAUTHFILL") {
            if parts[0] == "Tiempo de busqueda de peticiones pendientes de rellenar su autorizacion" {
                tag = "SCHSAUTHFILL_B";
            } else if parts[0].starts_with("Tiempo en encolar") {
                tag = "SCHSAUTHFILL_EN";
            } else {
                return Err(LineParseError {
                    line: line.to_string(),
                    message: format!("No debería ocurrir: {}", parts[0]),
                });
            }
        }
    }

    let texto = parts.remove(0).trim().to_string();
    if tag == "PETEXTAF" {
        parts.insert(0, texto);
    }
    parts.pop(); // Remove the last empty string

    let mut final_parts = vec![tag, pet_type, format!("{} {}", date, time), thread];
    final_parts.extend(parts);

    Ok(final_parts)
}

fn main() {
    let line = "java:12345] 2021-09-01 12:34:56 INFO 12345-THREAD-1234567890 [DBIMSG Insertado el mensaje de peticion externa]";
    match parse_line(line) {
        Ok(parsed_line) => println!("{:?}", parsed_line),
        Err(e) => eprintln!("Error parsing line '{}': {}", e.line, e.message),
    }
}

