```rust
use regex::Regex;
use log::{warn, error};

fn get_line(line: &str) -> Vec<String> {
    let line = line.replace(",", ".", 1);
    let re = Regex::new(r"(java:\d+]) ").unwrap();
    let a: Vec<&str> = re.split(line, 3).collect();

    if a.len() != 3 {
        warn!("Se esperaban 3 elementos en esta línea pero se han obenido {}", a.len());
        warn!("{}", line);
        return Vec::new();
    }

    let (general, general_ln, log) = (a[0], a[1], a[2]);
    let general = format!("{}{}", general, general_ln);
    let mut parts: Vec<&str> = general.split(" ").take(6).collect();

    let thread = parts[3].replace("^\\[.*-\\d+-", "").replace("^.*#", "").replace("]", "", 1);
    let thread = if !thread.is_empty() { format!("#{}", thread) } else { "".to_string() };

    let log = log.trim().to_string();

    // casos de los guiones: IDSOLEQ DBIMSG
    if log.contains("solicitudes-") {
        log.replace_inplace("solicitudes-", "solicitudes -");
    } else if log.contains("-Insertado") {
        log.replace_inplace("-Insertado", "- Insertado");
    }

    let parts: Vec<&str> = log.split(" - ").collect();

    assert!(parts.len() > 2, "Muy pocos tags en: {}", line);

    let pet_type = parts[0].replace("- ", "").to_string();
    let tag = parts[1].replace("[", "").replace("]", "").to_string();

    assert!(!tag.is_empty(), "Tag no encontrada en línea: {}", line);

    // casos especiales
    if tag == "DBIMSG" {
        if parts[2] == "Insertado el mensaje de peticion externa" {
            tag = "DBIMSG_PE".to_string();
        } else if parts[2] == "Insertado el mensaje de respuesta externa" {
            tag = "DBIMSG_RE".to_string();
        } else if parts[2] == "Insertado el mensaje de peticion intermediacion" {
            tag = "DBIMSG_PI".to_string();
        } else if parts[2] == "Insertado el mensaje de respuesta intermediacion" {
            tag = "DBIMSG_RI".to_string();
        } else {
            error!("No se esperaba mensaje: {} en línea\n{}\n", parts[2], line);
            return Vec::new();
        }
    }

    if tag == "EXTEPOL" { // caso en el que se usa - como vacío
        if parts[1] == parts[2] && parts[1] == "" {
            parts.remove(1);
        }
    }

    if ["DBIEXT", "DBIINT", "DBUEXT", "DBUINT"].contains(&tag.as_str()) {
        let cod_estado_cod_error = parts[parts.len() - 2].split("](").collect::<Vec<&str>>();
        parts.pop();
        parts.pop();
        parts.push(cod_estado_cod_error[0].trim_start_matches('[').to_string());
        parts.push(cod_estado_cod_error[1].trim_end_matches(']').to_string());
    }

    if tag == "SCHSAUTHFILL" {
        if parts[0] == "Tiempo de busqueda de peticiones pendientes de rellenar su autorizacion" {
            tag = "SCHSAUTHFILL_B".to_string();
        } else if parts[0].starts_with("Tiempo en encolar") {
            tag = "SCHSAUTHFILL_EN".to_string();
        } else {
            error!("No debería ocurrir: {}", parts[0]);
        }
    }

    let texto = parts.remove(0);

    if tag == "PETEXTAF" { // otro caso especial. Este tag no lleva texto
        parts.insert(0, texto);
    }

    parts[parts.len() - 1] = parts[parts.len() - 1].replace("?", "");

    let mut result = vec![tag, pet_type, format!("{} {}", parts[0], parts[1]), thread];
    result.extend(parts[2..].iter().map(|s| s.to_string()));

    result
}
