    let texto = parts.remove(0).trim().to_string();
    if tag == "PETEXTAF" {
        parts.insert(0, texto);
    }
    parts.pop(); // Remove the last empty string

    let mut final_parts = vec![tag, pet_type, format!("{} {}", date, time), thread];
    final_parts.extend(parts);

    Ok(final_parts)
}

